#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        unsigned int A,B,C; scanf("%u %u %u", &A, &B, &C);
        bool dp[2] = {true,false}, ndp[2];
        for(int bit=0; bit<31; ++bit){
            ndp[0]=ndp[1]=false;
            int a = (A>>bit)&1;
            int b = (B>>bit)&1;
            int c = (C>>bit)&1;
            for(int carry=0; carry<2; ++carry) if(dp[carry]){
                for(int x=0; x<2; ++x){
                    int a1 = a ^ x;
                    int b1 = b ^ x;
                    int c1 = c ^ x;
                    int sum = a1 + b1 + carry;
                    int bitRes = sum & 1;
                    int ncarry = sum >> 1;
                    if(bitRes == c1) ndp[ncarry] = true;
                }
            }
            dp[0]=ndp[0]; dp[1]=ndp[1];
        }
        puts(dp[0] ? "YES" : "NO");
    }
    return 0;
}

