import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int A = fs.nextInt();
            int B = fs.nextInt();
            int C = fs.nextInt();
            boolean[] dp = {true, false};
            boolean[] ndp = new boolean[2];
            for (int bit = 0; bit < 31; ++bit) {
                ndp[0] = ndp[1] = false;
                int a = (A >> bit) & 1;
                int b = (B >> bit) & 1;
                int c = (C >> bit) & 1;
                for (int carry = 0; carry < 2; ++carry) if (dp[carry]) {
                    for (int x = 0; x < 2; ++x) {
                        int a1 = a ^ x;
                        int b1 = b ^ x;
                        int c1 = c ^ x;
                        int sum = a1 + b1 + carry;
                        int bitRes = sum & 1;
                        int ncarry = sum >> 1;
                        if (bitRes == c1) ndp[ncarry] = true;
                    }
                }
                dp[0] = ndp[0];
                dp[1] = ndp[1];
            }
            sb.append(dp[0] ? "YES" : "NO").append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for speed
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

