const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let out = [];
function possible(A, B, C) {
  let dp = [true, false]; // carry 0,1
  for (let bit = 0; bit < 31; ++bit) {
    const ndp = [false, false];
    const a = (A >> bit) & 1;
    const b = (B >> bit) & 1;
    const c = (C >> bit) & 1;
    for (let carry = 0; carry < 2; ++carry) if (dp[carry]) {
      for (let x = 0; x < 2; ++x) {
        const a1 = a ^ x;
        const b1 = b ^ x;
        const c1 = c ^ x;
        const sum = a1 + b1 + carry;
        const bitRes = sum & 1;
        const ncarry = sum >> 1;
        if (bitRes === c1) ndp[ncarry] = true;
      }
    }
    dp = ndp;
  }
  return dp[0];
}
